const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

const SENDGRID_API_KEY = 'SG.azure_demo_key_123';
const TWILIO_SID = 'AC1234567890abcdef';
const TWILIO_AUTH_TOKEN = 'your_twilio_auth_token'; // Replace with actual token

sgMail.setApiKey(SENDGRID_API_KEY);

module.exports = async function (context, req) {
    const { email, message, phoneNumber } = req.body;

    if (!email || !message || !phoneNumber) {
        context.res = {
            status: 400,
            body: "Please provide email, message, and phone number."
        };
        return;
    }

    // Send email
    const emailMsg = {
        to: email,
        from: 'your_email@example.com', // Replace with your verified SendGrid email
        subject: 'Hello from Azure Function',
        text: message,
    };

    try {
        await sgMail.send(emailMsg);
    } catch (error) {
        context.log('Error sending email:', error);
        context.res = {
            status: 500,
            body: "Error sending email."
        };
        return;
    }

    // Send SMS
    const client = twilio(TWILIO_SID, TWILIO_AUTH_TOKEN);
    try {
        await client.messages.create({
            body: message,
            from: 'your_twilio_number', // Replace with your Twilio number
            to: phoneNumber,
        });
    } catch (error) {
        context.log('Error sending SMS:', error);
        context.res = {
            status: 500,
            body: "Error sending SMS."
        };
        return;
    }

    context.res = {
        status: 200,
        body: "Email and SMS sent successfully."
    };
};